mapper.select:
SELECT COUNT(um.id) FROM tb_user_message um INNER JOIN tb_message m ON um.message_id = m.id WHERE um.user_id = #{userId} AND um.is_read = 0 AND um.is_delete = 0 AND m.is_delete = 0 AND m.is_send = 1
AND m.client_type IN
#{item}

mapper.update:
UPDATE tb_user_message um INNER JOIN tb_message m ON um.message_id = m.id SET um.is_read = 1, um.read_time = NOW(), um.update_time = NOW() WHERE um.user_id = #{userId} AND um.is_read = 0 AND um.is_delete = 0 AND m.is_delete = 0
AND m.client_type IN
#{item}

mapper.select:
SELECT m.id, m.content, m.title, m.create_time AS createTime, m.type
FROM tb_user_message um
         JOIN tb_message m ON um.message_id = m.id
WHERE um.message_id = #{messageId}
  AND um.user_id = #{userId}
  AND um.is_delete = 0
